ShowOakGameLiveEditor=function()
  local I=0;
  if UE.OakGameLiveEditor then;
   UE.OakGameLiveEditor.destroy();
  end
  local function IntColorToABGR(colorInt)
   local TBL=DwordToByteTable(colorInt)
   return {R=TBL[1],G=TBL[2],B= TBL[3]}
  end
  local function ABGRToIntColor(TBL)
   return tonumber(string.format("%02X%02X%02X",TBL.B,TBL.G,TBL.R),16)
  end
  local function RGBFlate(TBL, amount)
   local brightness = (TBL.R + TBL.G + TBL.B) / 3
   if brightness > 127.5 then
    return {
     R=math.max(TBL.R - amount, 0),
     G=math.max(TBL.G - amount, 0),
     B=math.max(TBL.B - amount, 0)
    }
   else
    return {
     R= math.min(TBL.R + amount, 0xFF),
     G= math.min(TBL.G + amount, 0xFF),
     B= math.min(TBL.B + amount, 0xFF)
    }
   end
  end
  --Setup Colors
  local BaseColor=GetMainForm().RGBColor;
  local BaseRGB = IntColorToABGR(BaseColor)
  local Flate=RGBFlate(BaseRGB, 0x20)
  local SplitterColor =ABGRToIntColor(Flate)
  local brightness = (BaseRGB.R + BaseRGB.G + BaseRGB.B) / 3
  Flate=RGBFlate(BaseRGB, brightness<100 and 0x1C or 0x55)
  local BtnColor =ABGRToIntColor(Flate)
  local BtnRGB = IntColorToABGR(BtnColor)
  BtnRGB.G=brightness<100 and math.ceil(BtnRGB.G-(BtnRGB.G/1.5)) or math.ceil(BtnRGB.G/2);
  BtnRGB.B=brightness<100 and math.ceil(BtnRGB.B-(BtnRGB.B/1.5)) or math.ceil(BtnRGB.B/2);
  local BtnDisabledColor=ABGRToIntColor(BtnRGB);
  BtnRGB = IntColorToABGR(BtnColor)
  BtnRGB.R=brightness<100 and math.ceil(BtnRGB.R-(BtnRGB.R/1.5)) or math.ceil(BtnRGB.R/2);
  BtnRGB.B=brightness<100 and math.ceil(BtnRGB.B-(BtnRGB.B/1.5)) or math.ceil(BtnRGB.B/2);
  local BtnEnabledColor=ABGRToIntColor(BtnRGB);
  local CreateControl = function(Type, Owner, Name, Hint, Align, Anchors, Width, Height, Left, Top, Alignment, Layout, Color, FontSize, BorderStyle, ReadOnly, TabOrder,GetFlag,SetFlag)
   Type = Type:lower()
   local C = nil
   Hint = Hint or ""
   Align = Align or "alNone"
   Anchors = Anchors or "[akTop,akLeft]"
   Width = Width or 100
   Height = Height or 20
   Left = Left or 0
   Top = Top or 0
   Color = Color or nil
   FontSize = FontSize or (Owner and Owner.Font and Owner.Font.Size) or 9
   BorderStyle = BorderStyle or nil
   ReadOnly = ReadOnly or nil
   TabOrder = TabOrder or 0
   if Type == "panel" then
    C = createPanel(Owner)
    C.Parent = Owner
    C.Caption = Name or ""
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsNone"
    C.WordWrap = false
   elseif Type == "label" then
    C = createLabel(Owner)
    C.Parent = Owner
    C.Caption = Name or ""
    C.Align = Align
    C.Anchors = Anchors
    C.Alignment = Alignment or "taLeftJustify"
    C.Layout = Layout or "tlTop"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.WordWrap = false
   elseif Type == "button" then
    C = createCECustomButton(Owner)
    C.CustomDrawn=true;
    C.Parent = Owner
    C.Caption = Name or "Button"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
    C.Cursor = crHandPoint
    C.IsHovered = false
    C.IsPressed = false
    C.OnPaint = function(sender)
     local canvas = sender.Canvas
     local rect = {
      Left = 0,
      Top = 0,
      Right = sender.Width,
      Bottom = sender.Height
     }
     local bgColor = sender.ToggleState and BtnColor or (C.Color or BtnColor)
     local borderColor = 0x505050
     local textColor = 0xFFFFFF
     if sender.IsPressed then
      bgColor = (C.Color - 0x101010)
      borderColor = 0x707070
     elseif sender.IsHovered then
      bgColor =(C.Color + 0x101010)
      borderColor = 0x606060
     end
     canvas.Brush.Color = bgColor
     canvas.Pen.Color = borderColor
     canvas.Pen.Width = 1
     canvas.fillRect(rect.Left, rect.Top, rect.Right, rect.Bottom)
     canvas.Pen.Color = borderColor
     canvas.moveTo(rect.Left, rect.Bottom - 1)
     canvas.lineTo(rect.Left, rect.Top)
     canvas.lineTo(rect.Right - 1, rect.Top)
     canvas.Font = sender.Font
     canvas.Font.Color = textColor
     canvas.Brush.Style = "bsClear"
     local textWidth = canvas.getTextWidth(sender.Caption)
     local textHeight = canvas.getTextHeight(sender.Caption)
     local textX = math.floor((sender.Width - textWidth) / 2)
     local textY = math.floor((sender.Height - textHeight) / 2)
     if sender.IsPressed then
      textX = textX + 1
      textY = textY + 1
     end
     canvas.TextOut(textX, textY, sender.Caption)
    end
    
    C.OnMouseEnter = function(sender)
     sender.IsHovered = true
     sender.Repaint()
    end
    C.OnMouseLeave = function(sender)
     sender.IsHovered = false
     sender.IsPressed = false
     sender.Repaint()
    end
    C.OnMouseDown = function(sender, button, x, y)
     if button == mbLeft then
      sender.IsPressed = true
      sender.Repaint()
     end
    end
    C.OnMouseUp = function(sender, button, x, y)
     if button == mbLeft then
      sender.IsPressed = false
      sender.Repaint()
     end
    end
    if GetFlag then
     C.onClick=GetFlag
    end
   elseif Type == "togglebutton" then
    C = createCECustomButton(Owner)
    C.CustomDrawn=true;
    C.Parent = Owner
    C.BaseText=Name;
    C.Caption = Name or "Button"
    if Hint==nil or Hint=="" then;
     Hint="Enable / Disable "..C.BaseText;
    end
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
    C.Cursor = crHandPoint
    C.IsHovered = false
    C.IsPressed = false
    C.ToggleState = false
    C.GetFlag=GetFlag;
    C.SetFlag=SetFlag;
    C.ToggleStateUpdate=function()
     C.ToggleState=GetFlag and GetFlag() or false;
     C.Color=C.ToggleState and BtnEnabledColor or BtnDisabledColor;
     C.Caption=C.BaseText..(C.ToggleState and ": On" or ": Off");
     C.Repaint();
    end
    C.onClick=function();
     if C.SetFlag and C.GetFlag then;
      C.ToggleState=C.SetFlag(not C.GetFlag());
      C.Color=C.ToggleState and BtnEnabledColor or BtnDisabledColor;
      C.Caption=C.BaseText..(C.ToggleState and ": On" or ": Off");
      C.Repaint();
     end
    end

    C.OnPaint = function(sender)
     local canvas = sender.Canvas
     local rect = {
      Left = 0,
      Top = 0,
      Right = sender.Width,
      Bottom = sender.Height
     }
     local bgColor = sender.ToggleState and BtnEnabledColor or (C.Color or BtnDisabledColor)
     local borderColor = 0x505050
     local textColor = 0xFFFFFF
     if sender.IsPressed then
      bgColor = sender.ToggleState and (BtnEnabledColor - 0x101010) or (BtnDisabledColor - 0x101010)
      borderColor = 0x707070
     elseif sender.IsHovered then
      bgColor = sender.ToggleState and (BtnEnabledColor + 0x101010) or (BtnDisabledColor + 0x101010)
      borderColor = 0x606060
     end
     canvas.Brush.Color = bgColor
     canvas.Pen.Color = borderColor
     canvas.Pen.Width = 1
     canvas.fillRect(rect.Left, rect.Top, rect.Right, rect.Bottom)
     canvas.Pen.Color = borderColor
     canvas.moveTo(rect.Left, rect.Bottom - 1)
     canvas.lineTo(rect.Left, rect.Top)
     canvas.lineTo(rect.Right - 1, rect.Top)
     canvas.Font = sender.Font
     canvas.Font.Color = textColor
     canvas.Brush.Style = "bsClear"
     local textWidth = canvas.getTextWidth(sender.Caption)
     local textHeight = canvas.getTextHeight(sender.Caption)
     local textX = math.floor((sender.Width - textWidth) / 2)
     local textY = math.floor((sender.Height - textHeight) / 2)
     if sender.IsPressed then
      textX = textX + 1
      textY = textY + 1
     end
     canvas.TextOut(textX, textY, sender.Caption)
    end
    
    C.OnMouseEnter = function(sender)
     sender.IsHovered = true
     sender.Repaint()
    end
    C.OnMouseLeave = function(sender)
     sender.IsHovered = false
     sender.IsPressed = false
     sender.Repaint()
    end
    C.OnMouseDown = function(sender, button, x, y)
     if button == mbLeft then
      sender.IsPressed = true
      sender.Repaint()
     end
    end
    C.OnMouseUp = function(sender, button, x, y)
     if button == mbLeft then
      sender.IsPressed = false
      sender.Repaint()
     end
    end
    
    if C.GetFlag and C.SetFlag then
     C.ToggleStateUpdate();
    end
   elseif Type == "edit" then
    C = createEdit(Owner)
    C.Parent = Owner
    C.Text = Name or ""
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsSingle"
    C.ReadOnly = ReadOnly or false
    C.TabOrder = TabOrder
   elseif Type == "memo" then
    C = createMemo(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsSingle"
    C.ReadOnly = ReadOnly or false
    C.WordWrap = false
    C.ScrollBars = "ssAutoBoth"
    C.TabOrder = TabOrder
    if Name and Name ~= "" then;C.Lines.Text = Name;end
   elseif Type == "listbox" then
    C = createListBox(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsSingle"
    C.TabOrder = TabOrder
   elseif Type == "combobox" then
    C = createComboBox(Owner)
    C.Parent = Owner
    C.Text = Name or ""
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
   elseif Type == "checkbox" then
    C = createCheckBox(Owner)
    C.Parent = Owner
    C.Caption = Name or "CheckBox"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
    if SetFlag then
     C.OnChange=SetFlag
    end
    C.Checked=GetFlag
   elseif Type == "radiobutton" then
    C = createRadioButton(Owner)
    C.Parent = Owner
    C.Caption = Name or "RadioButton"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
   elseif Type == "groupbox" then
    C = createGroupBox(Owner)
    C.Parent = Owner
    C.Caption = Name or "GroupBox"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
   elseif Type == "pagecontrol" then
    C = createPageControl(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.TabOrder = TabOrder
   elseif Type == "splitter" then
    C = createSplitter(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    if Color then;C.Color = Color;end
   elseif Type == "treeview" then
    C = createTreeView(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsSingle"
    C.ReadOnly = ReadOnly or false
    C.TabOrder = TabOrder
   elseif Type == "listview" then
    C = createListView(Owner)
    C.Parent = Owner
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
    C.Align = Align
    C.Anchors = Anchors
    C.BorderStyle = BorderStyle or "bsSingle"
    C.TabOrder = TabOrder
   elseif Type == "tab" then
    C = Owner.addTab()
    C.Parent = Owner
    C.Caption = Name or "Tab"
    C.Hint = Hint
    C.ShowHint = Hint ~= ""
   end
   if C then
    C.Left = Left
    C.Top = Top
    C.Width = Width
    C.Height = Height
    if Owner and Owner.Font then;C.Font = Owner.Font;end
    if Color then;C.RGBColor = Color;end
    if FontSize and C.Font and FontSize ~= C.Font.Size then;C.Font.Size = FontSize;end
    if BorderStyle and C.BorderStyle ~= nil then;C.BorderStyle = BorderStyle;end
   end
   return C
  end
  local LastSelectedPlayerIndex=0;
  local SimpleToggleButton=function(Owner, Name, Hint, Align, Anchors, Width, Height, Left, Top, Alignment, Layout, Color, FontSize, BorderStyle, ReadOnly, TabOrder,EffectSelectedPlayer,Flag);
   return CreateControl("ToggleButton",Owner, Name, Hint, Align, Anchors, Width, Height, Left, Top, Alignment, Layout, Color, FontSize, BorderStyle, ReadOnly, TabOrder,
    function();
     local P=UE.PlayerCache[(EffectSelectedPlayer and LastSelectedPlayerIndex or UE.LocalPlayer.Index)];
     return P and P[Flag] or false;
    end,
    function(Value);
     local P=UE.PlayerCache[(EffectSelectedPlayer and LastSelectedPlayerIndex or UE.LocalPlayer.Index)];
     if P then;P[Flag]=Value;end
     return Value;
    end);
   end
  UE.OakGameLiveEditor = CreateControl("Panel",getAddressList().Parent.Parent,"OakGameLiveEditor",nil,"alBottom","[akTop,akLeft]",0,80,0,0,nil,nil,BaseColor);
  UE.OakGameLiveEditor.Font.Name = "Lucida Console";
  UE.OakGameLiveEditor.Font.Size = 9;
  OakGameLiveEditorInit();
  local TitleBar =CreateControl("Panel",UE.OakGameLiveEditor,"",nil,"alTop","[akTop,akLeft,akRight]",0,22,0,0);
  local CloseButton = CreateControl("Label",TitleBar,"[X]",nil,"alLeft",nil,22,22,0,0,"taCenter","tlCenter")
   CloseButton.Color = BaseColor;
   CloseButton.Font=createFont();
   CloseButton.Font.Name = "Lucida Console"
   CloseButton.Font.Size = 20
   CloseButton.Font.Color = 0x0000FF
   CloseButton.onClick=function();if UE.OakGameLiveEditor then;UE.OakGameLiveEditor.Close=true;end;end
  local TitleLabel = CreateControl("Label",TitleBar,"dr NHA's Borderlands4 Live Editor V: "..NHA_Borderlands4TableVersion,nil,"alClient",nil,0,0,0,0,"taCenter","tlCenter");TitleLabel.Color = BaseColor
  local ToolTabs = CreateControl("PageControl",UE.OakGameLiveEditor,nil,nil,"alClient","[akTop,akLeft,akRight,akBottom]");ToolTabs.TabOrder = 1
  local Connection =CreateControl("Tab",ToolTabs,"Connection","");
  local ConnectionPanel = CreateControl("Panel",Connection,"","","alClient","[akTop,akLeft,akRight,akBottom]",1245,633,0,0,nil,nil,BaseColor,9,"bsNone",nil,0)
  local AttachPanel = CreateControl("Panel",ConnectionPanel,"","","alTop","[akTop,akLeft,akRight]",1243,30,1,26,nil,nil,BaseColor,9,"bsNone",nil,0)
  local Hook = CreateControl("Edit",AttachPanel,"Please Attach!","","alClient","[akTop,akLeft,akRight,akBottom]",1118,28,124,1,nil,nil,BaseColor,9,"bsSingle",true,1)
  local AttachBtn = CreateControl("Button",AttachPanel,"Attach","Click To Initialize The Attach To The Game","alLeft","[akTop,akLeft,akBottom]",123,28,1,1,nil,nil,BtnColor,9,nil,nil,0,
   function(); if OpenProcess("Borderlands4.exe") then;createThread(UE.Find);end; end)
  local Logs = CreateControl("Memo",ConnectionPanel,"","","alClient","[akTop,akLeft,akRight,akBottom]",1243,576,1,56,nil,nil,BaseColor,9,"bsSingle",true,1)
  UE.OakGameLiveEditor.Logs=Logs;
  if not UE.OriginalPrint then;
   UE.OriginalPrint=print;
   UE.OriginalPrintVerbose=true;
   print=function(...)
    if UE and UE.OakGameLiveEditor and UE.OakGameLiveEditor.Logs then;
     UE.OakGameLiveEditor.Logs.append(...);
     if not UE.OriginalPrintVerbose then
      return;
