   function()
    createThread(function()
     print("Checking for updates...")
     local currentVersion = (NHA_Borderlands4TableVersion or 1)
     local downloadUrl = "https://github.com/dr-NHA/NHA_Borderlands4/releases/latest"
     local internet = getInternet()
     if not internet then
      print("Error: Internet functions are broken in your cheat engine build!")
      return
     end
     local success, response = pcall(function();
     return internet.getURL("https://raw.githubusercontent.com/dr-NHA/NHA_Borderlands4/main/version.txt");end);
     if not success or not response or response == "" then
      print("Error: Could not connect to GitHub to check for updates\n"..response)
      return
     end

     local latestVersion = response and response:match("^%s*(.-)%s*$")
     if not latestVersion or latestVersion == "" then
      print("Error: Could not parse version from GitHub")
      return
     end
     
     if tonumber(latestVersion)>currentVersion then
      print(string.format("New version available: %s (current: %s)", latestVersion, currentVersion))
      local result = messageDialog(
       string.format("A new version is available!\n\nCurrent version: %s\nLatest version: %s\n\nWould you like to open the download page?", currentVersion, latestVersion),
       mtConfirmation,
       mbYes, mbNo
      )
      if result == mrYes then
       shellExecute(downloadUrl)
      end
     else
      print(string.format("You are running the latest version (%s)", currentVersion))
     end
    end)
   end)

