   local function CreateRaritySlider(parent, labelText, offset, defaultValue, top)
    local panel = CreateControl("Panel", parent, "", "", "alTop", "[akTop,akLeft,akRight]", 0, 50, 5, top, nil, nil, BaseColor, 9, "bsNone", nil, 0);
    local label = CreateControl("Label", panel, labelText .. ": " .. string.format("%.2f", defaultValue), "", "alTop", "[akTop,akLeft,akRight]", 0, 18, 5, 2, "taLeftJustify", "tlCenter", BaseColor, 9, nil, nil, 0);
    local trackBar = createTrackBar(panel);
    trackBar.Parent = panel;
    trackBar.Align = "alTop";
    trackBar.Min = 0;
    trackBar.Max = 1000;
    trackBar.Position = math.floor(defaultValue * 100);
    trackBar.Frequency = 10;
    trackBar.TickStyle = "tsAuto";
    trackBar.Height = 28;
    trackBar.Left = 5;
    trackBar.Top = 20;
    
    trackBar.OnChange = function()
     local value = trackBar.Position / 100.0;
     label.Caption = labelText .. ": " .. string.format("%.2f", value);
      offset(value);
    end
    
    return trackBar;
   end
