     SendPlayerToWaypoint.onClick=function()
      local P=UE.PlayerCache[LastSelectedPlayerIndex];
      if P  then;
       local RC=readPointer(P.Pawn+UE.Offset.RootComponent);
       local OFFSET=UE.GetOffsetBySymbol("OakPlayerState.DiscoveryPinningState")+UE.GetOffsetBySymbol("GbxDiscoveryPinningState.PinnedDatas")
       local F=readInteger(P.State+OFFSET+0x8);
       F=(F and F>0) and ReadPointer(P.State+OFFSET) or nil;
       if F then;
        local WorldCheck=readQword(F+0x68);

        if WorldCheck==0 then
        F=F+UE.GetOffsetBySymbol("GbxDiscoveryPinningPinData.PinnedCustomWaypointLocation");
        UE.PlayerCache[LastSelectedPlayerIndex].Noclip_X = readDouble(F);
        UE.PlayerCache[LastSelectedPlayerIndex].Noclip_Y = readDouble(F+0x8);
        UE.PlayerCache[LastSelectedPlayerIndex].Noclip_Z = readDouble(F+(0x8*2));
        writeDouble(RC+0x260,UE.PlayerCache[LastSelectedPlayerIndex].Noclip_X);
        writeDouble(RC+0x268,UE.PlayerCache[LastSelectedPlayerIndex].Noclip_Y);
        writeDouble(RC+0x270,UE.PlayerCache[LastSelectedPlayerIndex].Noclip_Z);
        else
        
        local FA=0;
        UE.ActorArrayDo(function(Address)
         if not Address or not UE.IsPlayerType(Address) then return end
         if readInteger(Address+0x18)==WorldCheck then;
          FA=Address;
         end
        end);

        if FA==0 then return; end
        printf("%X. FOUND WAYPOINT",FA);
        return;
        end

        createThread(function();
         local III=LastSelectedPlayerIndex;
         sleep(100);
         local FU=0;
         local INC=20;
         --UE.PlayerCache[III].Noclip_Z=readFloat(P.Movement+UE.Offset.ReplicatedSwimmingState_SurfaceZ);
         for FU=0,20,1 do
          if readFloat(RC+0x4B0)==0 then;
          UE.PlayerCache[III].Noclip_Z=UE.PlayerCache[III].Noclip_Z+INC;
          INC=INC+5;
           writeDouble(RC+0x270,UE.PlayerCache[III].Noclip_Z);
          sleep(20);
          else
           break;
          end
         end
        end);


       end
      end
     end
