    local SetSkills=function(P,State)
     CreateThread(function()
      local Skills=P.Pawn;
      if not Skills then
       printf("Cannot Find Skills For User Index "..LastSelectedPlayerIndex);
       return
      end
      local B=readInteger(Skills+0x6DF8);
      local A=readPointer(Skills+0x6DF0);
      local C=0;
      local D=0;
      local E=0;
      local F=0;local G=0;
      print("Total Trees: "..B);
      local BState=State and 1 or 0;
      local IState=State and 999 or 0
      for C=0,B,1 do
       D=readPointer(A+(0x8*C));
       if D then
        E=UE.GetName(readInteger(D+0x108));
        if E then
         local Nodes=ReadPointer(D+0x138);
         local NodesC=ReadInteger(D+0x140);
         G=0;
         for F=0,NodesC-1,1 do
          writeByte(Nodes+G+0x90,BState);
          writeByte(Nodes+G+0x94,BState);
          writeByte(Nodes+G+0x91,BState);
          writeInteger(Nodes+G+0x98,IState);
          writeInteger(Nodes+G+0x9C,IState);
          G=G+0xA0+0x8;
         end
         local Groups=ReadPointer(D+0x148);
         local GroupsC=ReadInteger(D+0x150);
         G=0;
         for F=0,GroupsC-1,1 do
          writeByte(Groups+G+0x80,1);
          G=UE.AlignOffset(G+0x81);
         end
        end
       end
      end
     end)
     end

