    local function UpdatePlayerActiveWeaponInfo()
     local P = UE.PlayerCache[LastSelectedPlayerIndex]
     ActiveWeaponPartsListView.Items.Clear()
     if not P or not P.State then
      ActiveWeaponNameLabel.Caption = "Name: No Player Selected"
      ActiveWeaponTrueNameLabel.Caption = "Display Name: N/A"
      ActiveWeaponTypeLabel.Caption = "Type: Unknown"
      ActiveWeaponLevelLabel.Caption = "Level: 0"
      ActiveWeaponSlotLabel.Caption = "Slot: None"
      ActiveWeaponHandleLabel.Caption = "Handle: 0"
      ActiveWeaponPartStringEdit.Lines.Text = "None"
      return
     end
     
     local State = P.State
     local OffsetBase = UE.GetOffsetBySymbol("OakPlayerState.BackpackItems")
     local OffsetItems = UE.GetOffsetBySymbol("GbxItemSlotsContainer.items")
     local ArrayOffset = (OffsetBase and OffsetItems) and (OffsetBase + OffsetItems) or nil
     
     if not ArrayOffset then
      ActiveWeaponNameLabel.Caption = "Name: Error reading inventory"
      ActiveWeaponTrueNameLabel.Caption = "Display Name: N/A"
      ActiveWeaponTypeLabel.Caption = "Type: Unknown"
      ActiveWeaponLevelLabel.Caption = "Level: 0"
      ActiveWeaponSlotLabel.Caption = "Slot: None"
      ActiveWeaponHandleLabel.Caption = "Handle: 0"
      ActiveWeaponPartStringEdit.Lines.Text = "Error"
      return
     end
     
     local IActiveSlot = readInteger(State + UE.GetOffsetBySymbol("OakPlayerState.ActiveWeaponEquipSlot"))
     
     if not IActiveSlot or IActiveSlot == 255 then
      ActiveWeaponNameLabel.Caption = "Name: No Weapon Equipped"
      ActiveWeaponTrueNameLabel.Caption = "Display Name: N/A"
      ActiveWeaponTypeLabel.Caption = "Type: None"
      ActiveWeaponLevelLabel.Caption = "Level: 0"
      ActiveWeaponSlotLabel.Caption = "Slot: None"
      ActiveWeaponHandleLabel.Caption = "Handle: 0"
      ActiveWeaponPartStringEdit.Lines.Text = "None"
      return
     end
     
     local foundWeapon = false
     UE.ArrayAlgo(State, ArrayOffset, ArrayOffset + 8, 0x150, function(A, C)
      if readByte(A + 0x10D) == IActiveSlot then
       local typePointer = readPointer(A + 0x18)
       local infoPointer = readPointer(A + 0x20)
       local handle = readInteger(A + 0x108)
       local TRUENAME = UE.ReadItemNamingScheme(A,0x48);
       local itemName = "Unknown"
       if infoPointer and infoPointer ~= 0 then
        local namePointer = readPointer(infoPointer + 0x48)
        if namePointer and namePointer ~= 0 then
         itemName = UE.GetName(namePointer) or "Unknown"
        end
       end
       local itemType = "Unknown"
       if typePointer and typePointer ~= 0 then
        local typeNamePointer = readPointer(typePointer + 0x3C)
        if typeNamePointer and typeNamePointer ~= 0 then
         itemType = UE.GetName(typeNamePointer) or "Unknown"
        end
       end
       local partsPointer = readPointer(A + 0xB8)
       local partsString = readString(partsPointer, 1000)
       local Level = 0
       if partsString then
        local partsBytesHex, partsBytes = B85.decode(partsString)
        local partsBits = B85.bytesToBits(partsBytes)
        local LevelData = partsBits and B85.itemDecodeLevel(partsBits)
        Level = LevelData and LevelData.level or 0
       end
       
       ActiveWeaponNameLabel.Caption = "Name: " .. itemName
       ActiveWeaponTrueNameLabel.Caption = "Display Name: " .. (TRUENAME or "N/A")
       ActiveWeaponTypeLabel.Caption = "Type: " .. itemType
       ActiveWeaponLevelLabel.Caption = "Level: " .. tostring(Level)
       ActiveWeaponSlotLabel.Caption = "Slot: " .. tostring(IActiveSlot)
       ActiveWeaponHandleLabel.Caption = "Handle: " .. tostring(handle or 0)
       ActiveWeaponPartStringEdit.Lines.Text = partsString or "None"
       
       local Parts = ReadPointer(A + 0x28)
       local PartsCount = readInteger(A + 0x30)
       if Parts and PartsCount and PartsCount > 0 then
        for i = 0, PartsCount - 1 do
         local partPointer = ReadPointer(Parts + (i * 8))
         if partPointer and partPointer ~= 0 then
          local InnerPartTypeId = ReadInteger(partPointer + 0x20)
          local InnerPartType = UE.GetName(InnerPartTypeId)
          local PartTypeId = ReadInteger(partPointer + 0x40)
          local PartType = UE.GetName(PartTypeId)
          local PartId = ReadInteger(readPointer(partPointer + 0x68))
          local PartName = UE.GetName(PartId)
          
          PartType = UE.IsValidString(PartType) and PartType or "Unknown"
          PartName = UE.IsValidString(PartName) and PartName or "Unknown"
          InnerPartType = UE.IsValidString(InnerPartType) and InnerPartType or "Unknown"
          
          local listItem = ActiveWeaponPartsListView.Items.Add()
          if PartName ~= "Unknown" and PartType ~= "Unknown" then
           listItem.Caption = PartType
           listItem.SubItems.Add(PartName)
           --listItem.SubItems.Add(PartType .. "." .. PartName)
          elseif InnerPartType ~= "Unknown" then
           listItem.Caption = InnerPartType
           listItem.SubItems.Add("")
           --listItem.SubItems.Add(InnerPartType)
          else
           listItem.Caption = "Unknown Part " .. i
           listItem.SubItems.Add("")
           --listItem.SubItems.Add("Unknown")
          end
         end
        end
       end
       
       foundWeapon = true
       return true
      end
      return false
     end)
     
     if not foundWeapon then
      ActiveWeaponNameLabel.Caption = "Name: Weapon Not Found"
      ActiveWeaponTrueNameLabel.Caption = "Display Name: N/A"
      ActiveWeaponTypeLabel.Caption = "Type: Unknown"
      ActiveWeaponLevelLabel.Caption = "Level: 0"
      ActiveWeaponSlotLabel.Caption = "Slot: " .. tostring(IActiveSlot)
      ActiveWeaponHandleLabel.Caption = "Handle: 0"
      ActiveWeaponPartStringEdit.Lines.Text = "Not Found"
     end
    end
    UE.OakGameLiveEditor.UpdatePlayerActiveWeaponInfo=UpdatePlayerActiveWeaponInfo;
    ActiveWeaponRefreshBtn.onClick = function()
     UpdatePlayerActiveWeaponInfo()
    end
    ActiveWeaponCopyBtn.onClick = function()
      local P = UE.PlayerCache[LastSelectedPlayerIndex]
      if not P or not P.State then
       print("No player selected")
       return
      end
      UE.CopyActiveWeaponFromPlayerState(P.State,UE.LocalPlayer.State);
    end
    ActiveWeaponDumpBtn.onClick = function()
     createThread(function()
      local P = UE.PlayerCache[LastSelectedPlayerIndex]
      if not P or not P.State then
       print("No player selected")
       return
      end
      
      local State = P.State
      local OffsetBase = UE.GetOffsetBySymbol("OakPlayerState.BackpackItems")
      local OffsetItems = UE.GetOffsetBySymbol("GbxItemSlotsContainer.items")
      local ArrayOffset = (OffsetBase and OffsetItems) and (OffsetBase + OffsetItems) or nil
      
      if not UE.ArrayAlgo or not State or not ArrayOffset then
       print("Failed to access inventory system")
       return
      end
      local IActiveSlot = readInteger(State + UE.GetOffsetBySymbol("OakPlayerState.ActiveWeaponEquipSlot"))
      
      if not IActiveSlot or IActiveSlot == 255 then
       print("No weapon equipped")
       return
      end
      
      local weaponData = nil
      UE.ArrayAlgo(State, ArrayOffset, ArrayOffset + 8, UE.Offset.GbxItemContainerSlotEndCount, function(A, C)
       if readByte(A + 0x10D) == IActiveSlot then
        local item = UE.ReadGbxItemContainerSlot(A)
        if not item then
         print("Failed to read item data from slot!")
         return false
        end
        weaponData = {
         PartString = item.partsString,
         Type = item.name,
         WeaponType = item.type,
         ItemName = item.truename or item.name,
         Level = item.level or 0,
         DecodedPartString = item.DecodedPartString or "",
         Slot = IActiveSlot
        }
        return true
       end
       return false
      end)
      if not weaponData then
       print("Failed to find active weapon data!")
       return
      end
      
      local safeWeaponType = weaponData.WeaponType:gsub("[^%w%-_]", "_")
      local filename = "ActiveWeapon_" .. safeWeaponType .. ".txt"
      
      local dataLine = string.format(
       "PartString: %s | Type: %s | Level: %i | WeaponType: %s | ItemName: %s | DecodedPartString: %s | Slot: %i | Timestamp: %s\n",
       weaponData.PartString or "N/A",
       weaponData.Type or "N/A",
       weaponData.Level or 0,
       weaponData.WeaponType or "N/A",
       weaponData.ItemName or "N/A",
       weaponData.DecodedPartString or "N/A",
       weaponData.Slot or 0,
       os.date("%Y-%m-%d %H:%M:%S")
      )
      print(dataLine)
      local file = io.open(filename, "a")
      if file then
       file:seek("end", 0)
       local fileSize = file:seek()
       if fileSize == 0 then
        file:write("=== Active Weapon Dump for " .. safeWeaponType .. " ===\n")
        file:write("Generated: " .. os.date("%Y-%m-%d %H:%M:%S") .. "\n")
        file:write("Format: PartString | Type | Level | WeaponType | ItemName | DecodedPartString | Slot | Timestamp\n")
        file:write("================================================================================\n\n")
       end
       file:write(dataLine)
       file:close()
       print("Weapon data appended to: " .. filename)
      else
       print("Error: Could not open file " .. filename .. " for writing")
      end
     end)
    end
    
    PlayerInventoryPages.OnChange = function()
     if PlayerInventoryPages.ActivePage == ActiveWeaponTab then
      if not UE.OakGameLiveEditor.PlayerInventoryPages.ActiveWeaponTabShownOnce then
       UE.OakGameLiveEditor.PlayerInventoryPages.ActiveWeaponTabShownOnce = true
       UpdatePlayerActiveWeaponInfo()
      end
     end
    end
    UE.OakGameLiveEditor.PlayerInventoryPages=PlayerInventoryPages;
    UE.OakGameLiveEditor.PlayerInventoryPages.ActiveWeaponTabShownOnce = false
   end
  end

