    local nameLabel = CreateControl("Label", infoPanel, "Item: " .. (itemData.name or "Unknown"), "", "alTop", "[akTop,akLeft,akRight]", 790, 20, BaseColor, 2, "taLeftJustify", "tlCenter", nil, 10)
    local typeLabel = CreateControl("Label", infoPanel, "Type: " .. (itemData.type or "Unknown"), "", "alTop", "[akTop,akLeft,akRight]", 790, 20, BaseColor, 22, "taLeftJustify", "tlCenter", nil, 9)
    local handleLabel = CreateControl("Label", infoPanel, "Handle: " .. (itemData.handle or "0"), "", "alTop", "[akTop,akLeft,akRight]", 790, 20, BaseColor, 42, "taLeftJustify", "tlCenter", nil, 9)
    
    local levelPanel = CreateControl("Panel", infoPanel, "", "", "alTop", "[akTop,akLeft,akRight]", 790, 28, 0, 62, nil, nil, BaseColor, 9, "bsNone", nil, 0)
