    levelEdit.NumbersOnly = true
    local levelApplyBtn = CreateControl("Button", levelPanel, "Apply", "", "alLeft", "[akTop,akLeft]", 100, 26, 150, 1, nil, nil, BtnColor, 9, nil, nil, 2)
    
    local partsListView = CreateControl("ListView", mainPanel, "", "", "alClient", "[akTop,akLeft,akRight,akBottom]", 792, 270, 0, 110, nil, nil, BaseColor, 9, "bsSingle", nil, 0)
    partsListView.ViewStyle = "vsReport"
