    partsListView.Columns[2].Width = 280
    ]]
    local bottomPanel = CreateControl("Panel", mainPanel, "", "", "alBottom", "[akTop,akLeft,akRight,akBottom]", 792, 180, 0, 480, nil, nil, BaseColor, 9, "bsSingle", nil, 0)
    
    local partsStringLabel = CreateControl("Label", bottomPanel, "Raw Parts String:", "", "alTop", "[akTop,akLeft,akRight]", 790, 20, BaseColor, 2, "taLeftJustify", "tlCenter", nil, 9)
    local partsStringEdit = CreateControl("Memo", bottomPanel, itemData.partsString or "", "", "alTop", "[akTop,akLeft,akRight]", 790, 80, 2, 22, nil, nil, BaseColor, 9, "bsSingle", false, 0)
    partsStringEdit.ScrollBars = "ssBoth"
    partsStringEdit.WordWrap = false
  
    local decodedLabel = CreateControl("Label", bottomPanel, "Decoded Parts Preview:", "", "alTop", "[akTop,akLeft,akRight]", 790, 20, BaseColor, 105, "taLeftJustify", "tlCenter", nil, 9)
    local decodedEdit = CreateControl("Memo", bottomPanel, itemData.DecodedPartString or "", "", "alClient", "[akTop,akLeft,akRight,akBottom]", 790, 50, 2, 125, nil, nil, BaseColor, 9, "bsSingle", true, 0)
    decodedEdit.ScrollBars = "ssBoth"
    decodedEdit.WordWrap = false
  
    local buttonPanel = CreateControl("Panel", dialog, "", "", "alBottom", "[akTop,akLeft,akRight,akBottom]", 792, 35, 4, 529, nil, nil, BaseColor, 9, "bsNone", nil, 0)
    local refreshBtn = CreateControl("Button", buttonPanel, "Refresh Parts", "", "alLeft", "[akTop,akLeft,akBottom]", 100, 33, 2, 1, nil, nil, BtnColor, 9, nil, nil, 0)
    local applyBtn = CreateControl("Button", buttonPanel, "Apply Changes", "", "alRight", "[akTop,akRight,akBottom]", 100, 33, 689, 1, nil, nil, BtnColor, 9, nil, nil, 1)
    local cancelBtn = CreateControl("Button", buttonPanel, "Cancel", "", "alRight", "[akTop,akRight,akBottom]", 80, 33, 606, 1, nil, nil, BtnColor, 9, nil, nil, 2)
    
    local function PopulatePartsList()
     partsListView.Items.Clear()
     if not itemData.Address or itemData.Address == 0 then
      return
     end
     local Parts = ReadPointer(itemData.Address + 0x28)
     local PartsCount = readInteger(itemData.Address + 0x30)
     if not Parts or not PartsCount or PartsCount == 0 then
      return
     end
     for i = 0, PartsCount - 1 do
      local partPointer = ReadPointer(Parts + (i * 8))
      if partPointer and partPointer ~= 0 then
       local InnerPartTypeId = ReadInteger(partPointer + 0x20)
       local InnerPartType = UE.GetName(InnerPartTypeId)
       local PartTypeId = ReadInteger(partPointer + 0x40)
       local PartType = UE.GetName(PartTypeId)
       local PartId = ReadInteger(readPointer(partPointer + 0x68))
       local PartName = UE.GetName(PartId)
       PartType = UE.IsValidString(PartType) and PartType or "Unknown"
       PartName = UE.IsValidString(PartName) and PartName or "Unknown"
       InnerPartType = UE.IsValidString(InnerPartType) and InnerPartType or "Unknown"
       local listItem = partsListView.Items.Add()
       if PartName ~= "Unknown" and PartType ~= "Unknown" then
        listItem.Caption = PartType
        listItem.SubItems.Add(PartName)
        --listItem.SubItems.Add(PartType .. "." .. PartName)
       elseif InnerPartType ~= "Unknown" then
        listItem.Caption = InnerPartType
        listItem.SubItems.Add("")
        --listItem.SubItems.Add(InnerPartType)
       else
        listItem.Caption = "Unknown Part " .. i
        listItem.SubItems.Add("")
        --listItem.SubItems.Add("Unknown")
       end
      end
     end
    end
  
    local function UpdateDecodedPreview()
     local partsString = partsStringEdit.Lines.Text
     decodedEdit.Lines.Text = itemData.DecodedPartString or ""
    end
    
    refreshBtn.onClick = function()
     PopulatePartsList()
     UpdateDecodedPreview()
    end
  
    partsStringEdit.onChange = function()
     UpdateDecodedPreview()
    end
  
    applyBtn.onClick = function()
     local newPartsString = partsStringEdit.Lines.Text
     local newLevel = tonumber(levelEdit.Text)
     
     if newLevel and newLevel >= 1 and newLevel <= 50 then
     end
     if newPartsString and newPartsString ~= "" then
      if itemData.Address and itemData.Address ~= 0 then
       UE.SafeEditPartString(itemData.Address + 0xB8,newPartsString,false);
       print("Updated parts string for item: " .. (itemData.name or "Unknown"))
      end
     end
     dialog.ModalResult=1
     dialog.close()
    end
  
    cancelBtn.onClick = function()
     dialog.close()
    end
    levelApplyBtn.onClick = function()
     local newPartsString = partsStringEdit.Lines.Text
     local newLevel = tonumber(levelEdit.Text)
     local New = B85.encodeItemLevelInParts(newPartsString, newLevel)
     local Chq=B85.decodeItemLevelFromParts(New);
     if Chq.level==newLevel then
     partsStringEdit.Lines.Text=New
     else
     print("Failed To Set The Part String For: \nFailed To Encode The Correct Level:\nWanted Level: "..levelEdit.Text.."\nEncoded Level: "..Chq.level);
     end
    end
    
    levelEdit.OnKeyDown = function(sender, key, shift)
     if key == 13 then 
      levelApplyBtn.onClick()
      return true
     end
    end
    PopulatePartsList()
    UpdateDecodedPreview()
    
    return dialog.showModal(),dialog
   end

   local CreateInventoryView=function(Parent,GetBaseAddress,GetOffset,Equippable);
    local itemsCache = {};
    local sortColumn = -1;
    local sortAscending = false;
    
    local ListView = CreateControl("ListView",Parent,"","","alClient","[akTop,akLeft,akRight,akBottom]",0,0,0,0,nil,nil,BaseColor,9,"bsSingle",nil,0);
     ListView.ViewStyle = "vsReport";
     ListView.RowSelect = true;
     ListView.ReadOnly = true;
     ListView.GridLines = true;
     ListView.FullRowSelect = true;
     ListView.Columns.add();
     local COL=0;
     ListView.Columns[COL].Caption = "Slot";
     ListView.Columns[COL].Width = 48;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Name";
     ListView.Columns[COL].Width = 210;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Type";
     ListView.Columns[COL].Width = 130;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Level";
     ListView.Columns[COL].Width = 69;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Quantity";
     ListView.Columns[COL].Width = 78;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Flags";
     ListView.Columns[COL].Width = 58;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Handle";
     ListView.Columns[COL].Width = 60;COL=COL+1;
     if Equippable then;
      ListView.Columns.add();
      ListView.Columns[COL].Caption = "Equip Slot";
      ListView.Columns[COL].Width = 84;COL=COL+1;
     end
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "Locked";
     ListView.Columns[COL].Width = 60;COL=COL+1;
     ListView.Columns.add();
     ListView.Columns[COL].Caption = "PartString";
     ListView.Columns[COL].Width = 120;COL=COL+1;
     --[[  ListView.Columns.add();
     ListView.Columns[8].Caption = "Decoded Parts";
     ListView.Columns[8].Width = 200;]]
    local WaitingForRefresh=false;
    local function RefreshListViewDisplay()
     if not WaitingForRefresh then
      ListView.beginUpdate();
     end
     ListView.Items.Clear();
     for i, cachedItem in ipairs(itemsCache) do
      local listItem = ListView.Items.Add();
      listItem.Caption = string.format("%d", cachedItem.slot or 0);
      listItem.SubItems.Add(cachedItem.truename and cachedItem.truename or cachedItem.name or "");
      listItem.SubItems.Add(cachedItem.type or "");
      listItem.SubItems.Add(cachedItem.level or "");
      local quantityText = (cachedItem.quantity and tostring(cachedItem.quantity) or "0") .. " / " .. (cachedItem.maxQuantity and tostring(cachedItem.maxQuantity) or "0");
      listItem.SubItems.Add(quantityText);
      listItem.SubItems.Add(cachedItem.flags and string.format("0x%X", cachedItem.flags) or "0x0");
      listItem.SubItems.Add(cachedItem.handle and tostring(cachedItem.handle) or "0");
      if Equippable then;
       listItem.SubItems.Add(cachedItem.equipSlot == "" and "" or cachedItem.equipSlot and tostring(cachedItem.equipSlot) or "0");
      end
      listItem.SubItems.Add(cachedItem.isLocked and (cachedItem.isLocked ~= 0 and "Yes" or "No") or "No");
      --listItem.SubItems.Add(cachedItem.DecodedPartString or "");
      listItem.SubItems.Add(cachedItem.partsString or "");
     end
     ListView.endUpdate();
     WaitingForRefresh=false;
    end

    local function SortItems(column)
     if not WaitingForRefresh then;
      WaitingForRefresh=true;
      ListView.beginUpdate();
     end
      if sortColumn == column then
        sortAscending = not sortAscending;
      else
       if sortColumn~=-1 then;
        if ListView.Columns[sortColumn].Width-11<90 then;
         ListView.Columns[sortColumn].Width = ListView.Columns[sortColumn].Width-13;
        end
       end
       sortColumn = column;
       if ListView.Columns[sortColumn].Width<90 then
        ListView.Columns[sortColumn].Width = ListView.Columns[sortColumn].Width+13;
       end
       sortAscending = true;
      end
      for i = 0, ListView.Columns.Count - 1 do
        local caption = ListView.Columns[i].Caption;
        caption = string.gsub(caption, " %^", "");
        caption = string.gsub(caption, " v", "");
        if i == column then
          caption = caption .. (sortAscending and " ^" or " v");
        end
        ListView.Columns[i].Caption = caption;
      end
      table.sort(itemsCache, function(a, b)
        local valueA, valueB;
        if column == 0 then -- Slot
          valueA = a.slot or 0;
          valueB = b.slot or 0;
        elseif column == 1 then -- Name
          valueA = (a.name or ""):lower();
          valueB = (b.name or ""):lower();
        elseif column == 2 then -- Type
          valueA = (a.type or ""):lower();
          valueB = (b.type or ""):lower();
        elseif column == 3 then -- Quantity
          valueA = a.quantity or 0;
          valueB = b.quantity or 0;
        elseif column == 4 then -- Flags
          valueA = a.flags or 0;
          valueB = b.flags or 0;
        elseif column == 5 then -- Handle
          valueA = a.handle or 0;
          valueB = b.handle or 0;
        elseif column == 6 then -- Equip Slot
          if a.equipSlot == "" then valueA = 999999; else valueA = tonumber(a.equipSlot) or 0; end
          if b.equipSlot == "" then valueB = 999999; else valueB = tonumber(b.equipSlot) or 0; end
        elseif column == 7 then -- Locked
          valueA = (a.isLocked and a.isLocked ~= 0) and 1 or 0;
          valueB = (b.isLocked and b.isLocked ~= 0) and 1 or 0;
        elseif column == 8 then -- Decoded Parts
          valueA = (a.DecodedPartString or ""):lower();
          valueB = (b.DecodedPartString or ""):lower();
        else
          return false;
        end
        
        if sortAscending then
          return valueA < valueB;
        else
          return valueA > valueB;
        end
      end);
      RefreshListViewDisplay();
    end
  
    ListView.OnColumnClick = function(sender, column)
     SortItems(column.Index);
    end;
    local function GetSelectedItem()
     if ListView.Selected then
      local selectedIndex = ListView.ItemIndex;
      if selectedIndex >= 0 then
       return itemsCache[selectedIndex+1],selectedIndex;
      end
     end
     return nil,-1;
    end
    local ContextMenu = createPopupMenu(ListView);
    local EditItem = createMenuItem(ContextMenu);
    EditItem.Caption = "Edit Item";
    ContextMenu.Items.add(EditItem);
    local DeleteItem = createMenuItem(ContextMenu);
    DeleteItem.Caption = "Delete Item";
    DeleteItem.onClick = function()
     local cachedItem,selectedIndex=GetSelectedItem();
     if cachedItem then
      print("Delete item at index: " .. tostring(selectedIndex));
      print("Item Address: 0x" .. string.format("%X", cachedItem.Address));
     else
      print("No cached data for selected item");
     end
    end;
    ContextMenu.Items.add(DeleteItem);
    local Separator1 = createMenuItem(ContextMenu);
    Separator1.Caption = "-";
    ContextMenu.Items.add(Separator1);
    local CopyToMenu = createMenuItem(ContextMenu);
    CopyToMenu.Caption = "Copy to...";
    local CopyToBackpack = createMenuItem(CopyToMenu);
    CopyToBackpack.Caption = "Backpack";
    CopyToBackpack.onClick = function()
     local cachedItem,selectedIndex=GetSelectedItem();
     if cachedItem then
      UE.GbxItemContainerSlotCopyTo(cachedItem.Address,UE.LocalPlayer.State,(UE.Offset.OakPlayerStateBackpackItemsOffset and UE.Offset.GbxItemSlotsContainerItemsOffset) and (UE.Offset.OakPlayerStateBackpackItemsOffset+UE.Offset.GbxItemSlotsContainerItemsOffset) or nil);
      print("Copy item at index " .. tostring(selectedIndex) .. " to Backpack");
     else
      print("No cached data for selected item");
     end
    end;
    CopyToMenu.add(CopyToBackpack);
    local CopyToBank = createMenuItem(CopyToMenu);
    CopyToBank.Caption = "Bank";
    CopyToBank.onClick = function()
     local cachedItem,selectedIndex=GetSelectedItem();
     if cachedItem then
      UE.GbxItemContainerSlotCopyTo(cachedItem.Address,UE.LocalPlayer.State,(UE.Offset.OakPlayerStateBankItemsOffset and UE.Offset.GbxItemSlotsContainerItemsOffset) and (UE.Offset.OakPlayerStateBankItemsOffset+UE.Offset.GbxItemSlotsContainerItemsOffset) or nil);
      print("Copy item at index " .. tostring(selectedIndex) .. " to Bank");
     else
      print("No cached data for selected item");
     end
    end;
    CopyToMenu.add(CopyToBank);
    ContextMenu.Items.add(CopyToMenu);
    ListView.PopupMenu = ContextMenu;
    local LastListAddress=0;
    local function PopulateItems(CalledByAutomation)
     if not WaitingForRefresh then;
      WaitingForRefresh=true;
      ListView.beginUpdate();
     end
     itemsCache = {};
     ListView.Items.Clear();
     local Address =GetBaseAddress();
     if not Address or Address == 0 then
      return;
     end
     if CalledByAutomation then
      if LastListAddress and LastListAddress==Address then
       return
      end
     end
     local Offset=GetOffset();
     local Count=Offset and readInteger(Address+Offset+0x8) or nil;
     Address=Count and ReadPointer(Address+Offset) or nil;
     if not Address or Address == 0 or not Count or Count==0 then
      return;
     end
     Count=Count-1;
     local itemsAdded = 0;
     for i = 0, Count,1 do
      local itemOffset = Address + (UE.Offset.GbxItemContainerSlotEndCount * i);
      local item=UE.ReadGbxItemContainerSlot(itemOffset);
      if item then
       item.slot=i;
       table.insert(itemsCache, item);
       itemsAdded = itemsAdded + 1;
      end
     end
     if #itemsCache > 0 then
      if LastListAddress~=Address then;
       sortAscending=false;
       SortItems(sortColumn);
       LastListAddress=Address;
      else
       RefreshListViewDisplay();
      end
     else
      RefreshListViewDisplay();
     end
     if WaitingForRefresh then
      WaitingForRefresh=false;
      ListView.endUpdate();
     end
    end
    local RefreshBtn = CreateControl("Button",Parent,"Refresh","","alTop","[akLeft,akRight,akTop]",0,25,0,0,nil,nil,BtnColor,9,nil,nil,0);
    RefreshBtn.onClick =function(); PopulateItems();end;
    EditItem.onClick = function()
     local cachedItem,selectedIndex=GetSelectedItem();
     if cachedItem and CreatePartsEditDialog(cachedItem) then
      PopulateItems();
     end
    end;
    return ListView,RefreshBtn.onClick;
   end
   
   do;--Backpack
    Horizontal,Vertical=6,6;
    Width,Height=148,25;
    BackpackTab = CreateControl("Tab",InventoryPages,"Backpack");
    local BackpackTabPanel = CreateControl("Panel",BackpackTab,"","","alClient","[akTop,akLeft,akRight,akBottom]",0,0,0,0,nil,nil,BaseColor,9,"bsNone",nil,0);
    BackpackTabListView,BackpackTabPopulateItems=CreateInventoryView(BackpackTabPanel,
     function();
      return UE.LocalPlayer and UE.LocalPlayer.State;
     end,
     function();
      return UE.GetOffsetBySymbol("OakPlayerState.BackpackItems")+UE.GetOffsetBySymbol("GbxItemSlotsContainer.items");
     end,true);
   end
   
   do;--Bank
    Horizontal,Vertical=6,6;
    Width,Height=148,25;
    BankTab = CreateControl("Tab",InventoryPages,"Bank");
    local BankTabPanel = CreateControl("Panel",BankTab,"","","alClient","[akTop,akLeft,akRight,akBottom]",0,0,0,0,nil,nil,BaseColor,9,"bsNone",nil,0);
    BankTabListView,BankTabPopulateItems=CreateInventoryView(BankTabPanel,
     function();
      return UE.LocalPlayer and UE.LocalPlayer.State;
     end,
     function();
      return UE.GetOffsetBySymbol("OakPlayerState.BankItems")+UE.GetOffsetBySymbol("GbxItemSlotsContainer.items");
     end);
   end
   
   do;--Lost Loot
    Horizontal,Vertical=6,6;
    Width,Height=148,25;
    LostLootTab = CreateControl("Tab",InventoryPages,"Lost Loot");
    local LostLootTabPanel = CreateControl("Panel",LostLootTab,"","","alClient","[akTop,akLeft,akRight,akBottom]",0,0,0,0,nil,nil,BaseColor,9,"bsNone",nil,0);
 
   end
   
   local OldOnChange=InventoryPages.OnChange;
   InventoryPages.OnChange=function(...)
    if OldOnChange then;
     OldOnChange(...);
    end
    if InventoryPages.ActivePage==BackpackTab then;
     BackpackTabPopulateItems(true);
    elseif InventoryPages.ActivePage==BankTab then;
     BankTabPopulateItems(true);
    elseif InventoryPages.ActivePage==LostLootTab then;
     --LostLootTabPopulateItems(true);
    end
   end
  end;
  
  local OldToolTabsOnChange=ToolTabs.OnChange;
  ToolTabs.OnChange=function(...)
   if OldToolTabsOnChange then;
    OldToolTabsOnChange(...);
   end
   if ToolTabs.ActivePage.Name==Inventory.Name then;
    InventoryPages.OnChange(...);
   end
   local Player=UE.PlayerCache[UE.LocalPlayer.Index];
   if Player then;
    LP_GodMode.ToggleStateUpdate();
    LP_SuperSpeed.ToggleStateUpdate();
    LP_SuperJump.ToggleStateUpdate();
    LP_InfinateAmmo.ToggleStateUpdate();
    LP_MaxDamage.ToggleStateUpdate();
    LP_Noclip.ToggleStateUpdate();
    LP_MaxMoney.ToggleStateUpdate();
    LP_WalkUnderWater.ToggleStateUpdate();
    LP_InventoryIncrease.ToggleStateUpdate();
   end
   TpToCrosshair.ToggleStateUpdate();
  end
  
  local LastSelectedPlayerName="";
  local OldPlayerListOnMouseDown=PlayerList.OnMouseDown;
  PlayerList.OnMouseDown=function(...);
   LastSelectedPlayerName="";
   SelectedPlayerName.Caption="Selected Player:";
   PlayerManagerPages.Enabled=false;
   LastSelectedPlayerIndex=-1;
   local D=0;local Player=nil;local P=nil;
   for D=0,PlayerList.Items.Count-1 do;
    if PlayerList.Selected[D] then
     if LastSelectedPlayerName~=PlayerList.Items[D] then
      SelectedPlayerName.Caption="Selected Player: "..PlayerList.Items[D];
      LastSelectedPlayerName=PlayerList.Items[D];
      LastSelectedPlayerIndex=D+1;
      Player=UE.PlayerCache[LastSelectedPlayerIndex];
      if Player then;
       GodMode.ToggleStateUpdate();
       SuperSpeed.ToggleStateUpdate();
       SuperJump.ToggleStateUpdate();
       InfinateAmmo.ToggleStateUpdate();
       MaxDamage.ToggleStateUpdate();
       Noclip.ToggleStateUpdate();
       MaxMoney.ToggleStateUpdate();
       WalkUnderWater.ToggleStateUpdate();
       InventoryIncrease.ToggleStateUpdate();
       VehicleBoostHack.ToggleStateUpdate();
       EnableHackedJumpGoalDef.ToggleStateUpdate();
       HasUnlockedSpecializations.ToggleStateUpdate();
       SetLevelUp.ToggleStateUpdate();
       SetLevelUpS.ToggleStateUpdate();
       FreezePlayer.ToggleStateUpdate();
       Player=Player and Player.Pawn or nil;
       if Player then
       P=readPointer(Player+0x168);if P then;
       P=readPointer(P+0x398);if P then;
       P=readPointer(P+0x6C0);if P then;
       SetLevelEdit.Text=ReadInteger(P);
       SetLevelSEdit.Text=ReadInteger(P+0x60);
       end;end;end;

        Player=readPointer(Player+UE.Offset.Progression_PointsAcquiredPerPool);
        if Player then
         SetSpecPointsEdit.Text=readInteger(Player+0x4);
         SetSDUPointsEdit.Text=readInteger(Player+0x8);
        end
       end;
       PlayerManagerPages.Enabled=true;
      end
     end
     break;
    end
   end
   if OldPlayerListOnMouseDown then;
    OldPlayerListOnMouseDown(...);
   end
   UE.OakGameLiveEditor.UpdatePlayerActiveWeaponInfo();
  end

  PlayerList.OnMouseDown();
  SelectedPlayerName.Font=createFont();
  SelectedPlayerName.Font.Name = "Lucida Console"
  SelectedPlayerName.Font.Size = 11
  SelectedPlayerName.Font.Color = 0xAA559F
  UE.OakGameLiveEditor.Tag=1337;
  UE.LastPlayerHash="";
  UE.OakGameLiveEditor.AddTimerFunction(function();
   NotVis=not UE.FoundFinished or UE.FoundFinished==false;
   if ONotVis==nil or ONotVis~=NotVis then;
    Hook.Text=NotVis and "Please Attach!" or "Connected!";
   end
   if UE.CurPlayerHash~=UE.LastPlayerHash then
    Count=#UE.PlayerCache;
    if Count>0 then
     PlayerCount.caption=string.format(" Players: %i", #UE.PlayerCache);
     PlayerList.Items.setText(UE.CurPlayerHash);
    elseif UE.LastPlayerHash~="" then;
     UE.LastPlayerHash="";
     PlayerCount.caption=" Players: 0";
     PlayerList.Items.setText(UE.LastPlayerHash);
    end
   end;
   ONotVis=NotVis;
  end);

 end;FNR("ShowOakGameLiveEditor");